import{c as a,Q as o,j as r,m as t}from"./chunks/framework.Dja1PWb_.js";const p=JSON.parse('{"title":"Platform owner","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/personas/platform-owner.md","filePath":"concepts/personas/platform-owner.md"}'),n={name:"concepts/personas/platform-owner.md"};function i(s,e,l,h,d,c){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="platform-owner" tabindex="-1">Platform owner <a class="header-anchor" href="#platform-owner" aria-label="Permalink to &quot;Platform owner&quot;">​</a></h1><p>A platform owner operates Platform Mesh as the shared service-management layer for an organization. They make sure providers can publish services, consumers can safely use them, and the platform has a consistent account, identity, and authorization model.</p><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Create a secure and operable mesh where service capabilities can be offered and consumed without every team inventing its own integration pattern.</p><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><ul><li>Operate the Platform Mesh runtime and its core components.</li><li>Define the account hierarchy and workspace model used by providers and consumers.</li><li>Configure identity, authorization, and policy boundaries.</li><li>Onboard service providers and make their APIs discoverable.</li><li>Decide which components are installed, upgraded, and exposed to users.</li></ul><h2 id="ownership-boundary" tabindex="-1">Ownership boundary <a class="header-anchor" href="#ownership-boundary" aria-label="Permalink to &quot;Ownership boundary&quot;">​</a></h2><p>The platform owner owns the <strong>mesh itself</strong> — the control plane substrate, the account hierarchy, identity and authorization wiring, and the marketplace surface. They do not own provider implementations or consumer workloads. Their relationship to providers is onboarding and lifecycle; their relationship to consumers is enabling discovery, binding, and policy.</p><h2 id="common-questions" tabindex="-1">Common questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common questions&quot;">​</a></h2><ul><li>Which components are part of the Platform Mesh runtime?</li><li>How do accounts, workspaces, and control planes relate?</li><li>How are providers onboarded into the mesh?</li><li>Where are identity and authorization enforced?</li><li>Which operational tasks belong in Platform Mesh and which belong in provider runtimes?</li></ul><h2 id="recommended-reading" tabindex="-1">Recommended reading <a class="header-anchor" href="#recommended-reading" aria-label="Permalink to &quot;Recommended reading&quot;">​</a></h2><p>Start with <a href="./../why-platform-mesh.html">Why Platform Mesh?</a> for motivation, then read <a href="./../architecture.html">Architecture</a> for component layout, <a href="./../account-model.html">Account model</a> for the hierarchy, and <a href="./../control-planes.html">Control planes and workspaces</a> for how the kcp substrate is used. Use <a href="./../identity-and-authorization.html">Identity and authorization</a> for the runtime relationship between Keycloak, OpenFGA, and the kcp authorizer. Use <a href="/pr-preview/pr-222/reference/components/">Components</a> for factual component lookup.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./">Personas overview</a></li><li><a href="./service-provider.html">Service provider</a> — the role onboarded by platform owners</li><li><a href="./../account-model.html">Account model</a></li><li><a href="./../architecture.html">Architecture</a></li></ul>',14)])])}const u=a(n,[["render",i]]);export{p as __pageData,u as default};
